package com.vidaysalud.veterinaria.pagoservicio.client;
import com.vidaysalud.veterinaria.pagoservicio.exception.*;import lombok.RequiredArgsConstructor;import org.springframework.beans.factory.annotation.Value;import org.springframework.http.HttpStatusCode;import org.springframework.stereotype.Component;import org.springframework.web.reactive.function.client.*;import java.time.Duration;
@Component @RequiredArgsConstructor
public class ConsultaClient{private final WebClient.Builder builder;@Value("${servicios.consulta.url}")private String baseUrl;public void validar(Integer id){try{builder.build().get().uri(baseUrl+"/"+id).retrieve().onStatus(HttpStatusCode::is4xxClientError,r->r.createException().map(e->new ReglaNegocioException("Consulta no existe con id: "+id))).toBodilessEntity().block(Duration.ofSeconds(4));}catch(ReglaNegocioException e){throw e;}catch(WebClientRequestException e){throw new ServicioRemotoException("No fue posible conectar con consulta-servicio");}catch(Exception e){throw new ServicioRemotoException("Error consultando consulta-servicio");}}}
